1. Create src/hooks/useManifestOverlay.ts:
- Hook that merges original manifest quadrants with runtime overrides from World store
- Reads from world path 'ui.layout.quadrants' using useSlice
- Returns merged quadrant definitions: original config merged with overlay config
- If overlay has a config for a quadrantId, deep-merge it with the original

```typescript
import { useSlice } from './useSlice';
import { world } from '../world';
import { QuadrantManifest } from '../grid/QuadrantGrid';

export function useManifestOverlay(manifest: QuadrantManifest): QuadrantManifest {
  const overrides = useSlice(world, 'ui.layout.quadrants') as Record<string, any> | null;
  if (!overrides) return manifest;

  const merged = { ...manifest, quadrants: { ...manifest.quadrants } };
  for (const [qid, override] of Object.entries(overrides)) {
    if (merged.quadrants[qid]) {
      merged.quadrants[qid] = {
        ...merged.quadrants[qid],
        config: { ...(merged.quadrants[qid].config || {}), ...(override.config || {}) },
      };
    }
  }
  return merged;
}
```

